<div class="focus-panel"><div class="panel-heading"><h2>Routines</h2><button aria-label="Create routine">+</button></div><h3>Routine Tasks</h3>{#each ['Lift / Yoga / Meditate', 'Section of a book', 'Section of scripture'] as routine}<article><input type="checkbox" aria-label={routine} /><span>{routine}</span><small>Daily</small><b>⋮</b></article>{/each}</div>
<style>.focus-panel { display: grid; align-content: start; gap: .65rem; height: 100%; padding: 1.15rem 1rem; } .panel-heading { display: flex; align-items: center; justify-content: space-between; } h2, h3 { margin: 0; font-size: 1.05rem; } h3 { margin-top: .35rem; font-size: .85rem; } button { padding: .35rem .55rem; border: 1px solid var(--border-custom); border-radius: .35rem; background: var(--bg-elevated); color: var(--text-main); } article { display: grid; grid-template-columns: auto 1fr auto auto; align-items: center; gap: .5rem; padding: .8rem; border: 1px solid var(--border-custom); border-radius: .4rem; background: var(--bg-secondary); font-size: .78rem; } article input { width: 1.1rem; height: 1.1rem; } small { grid-column: 2; color: var(--text-muted); font-size: .65rem; } b { color: var(--text-muted); }</style>
